from flask import Flask, make_response

app = Flask(__name__)

@app.route('/set-cookie')
def set_cookie():
    resp = make_response("Cookie 'my_cookie' has been set!")
    resp.set_cookie('my_cookie', 'my_value', max_age=3600)  # max_age in seconds (1 hour)
    return resp

if __name__ == '__main__':
    app.run(debug=True)
